INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-025', 'Neuro', 'A 27-year-old man is brought to the operating room 9 days after a T6 spinal cord transection sustained in a motorcycle collision, now scheduled for urgent debridement and flap coverage of a sacral pressure injury complicated by sepsis. He has flaccid paraplegia below the level of injury. He is hypotensive and tachycardic, and the trauma surgeon requests a rapid-sequence induction because of a full stomach. The resident proposes succinylcholine 1.5 mg/kg to optimize intubating conditions. Which statement BEST describes the principal hazard of this plan?', '[{"text":"Succinylcholine will be ineffective because denervated muscle below the injury is resistant to depolarizing blockade","label":"A","correct":false,"rationale":"Denervated muscle is not resistant to succinylcholine; the problem is an exaggerated pharmacologic response, not failure of relaxation, so this misstates the risk."},{"text":"Succinylcholine will trigger malignant hyperthermia because spinal cord injury upregulates the ryanodine receptor","label":"B","correct":false,"rationale":"Spinal cord injury does not cause malignant-hyperthermia susceptibility, which is a genetic ryanodine-receptor channelopathy unrelated to denervation, so this is incorrect."},{"text":"Succinylcholine will cause a prolonged block because plasma cholinesterase activity is depleted after spinal cord injury","label":"C","correct":false,"rationale":"Pseudocholinesterase activity is not characteristically depleted by spinal cord injury, and prolonged block is not the feared catastrophic event in this setting."},{"text":"Succinylcholine is safe at this interval because receptor upregulation does not begin until roughly 6 months after injury","label":"D","correct":false,"rationale":"This is factually wrong: upregulation of extrajunctional acetylcholine receptors begins within a few days and is well established by the end of the first week, making this interval high-risk."},{"text":"Succinylcholine can precipitate life-threatening hyperkalemia and cardiac arrest from massive efflux through upregulated extrajunctional acetylcholine receptors","label":"E","correct":true,"rationale":"Within days of a denervating spinal cord injury, extrajunctional and immature (fetal-type) acetylcholine receptors proliferate, so depolarization releases a massive potassium load that can cause arrhythmia and cardiac arrest, which is the correct and most feared hazard."}]'::jsonb, 'E', 'After upper motor neuron injuries such as spinal cord transection, skeletal muscle proliferates extrajunctional and immature acetylcholine receptors. When succinylcholine depolarizes these widespread receptors, a large efflux of intracellular potassium can produce acute hyperkalemia, ventricular dysrhythmias, and cardiac arrest. The dangerous window opens within a few days of injury (receptor upregulation is established by roughly the end of the first week) and can persist for many months, so succinylcholine should be avoided well before and long after this 9-day mark. A nondepolarizing agent such as rocuronium is the appropriate choice for rapid-sequence induction in this patient.', '{}'::jsonb, 'Subspecialty Care', 'Succinylcholine-induced hyperkalemia after denervating spinal cord injury', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499984/","source":"Succinylcholine Chloride - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Neuro'),
('authored-batch-r20-026', 'Neuro', 'A 41-year-old woman recovers in the PACU after endoscopic transsphenoidal resection of a pituitary macroadenoma with suprasellar extension. Over the first 6 hours postoperatively she produces 350-450 mL/hr of clear, dilute urine. Her measurements show serum sodium 149 mEq/L (preoperatively 140), serum osmolality 304 mOsm/kg, and urine osmolality 110 mOsm/kg. She is awake and reports intense thirst but is otherwise hemodynamically stable. Which is the MOST appropriate next step in management?', '[{"text":"Replace ongoing free-water losses and administer desmopressin (DDAVP)","label":"A","correct":true,"rationale":"Hypotonic polyuria with a rising serum sodium, high serum osmolality, and inappropriately dilute urine after pituitary surgery is central diabetes insipidus, which is correctly treated by replacing free water and giving the ADH analogue desmopressin."},{"text":"Restrict free water and begin a hypertonic (3%) saline infusion to correct the sodium","label":"B","correct":false,"rationale":"This describes the management of SIADH-associated hyponatremia, the opposite electrolyte derangement, and would dangerously worsen this patient''s hypernatremia and free-water deficit."},{"text":"Administer a 20 mEq potassium chloride bolus and continue observation, attributing the polyuria to intraoperative fluid mobilization","label":"C","correct":false,"rationale":"The picture is dilute polyuria with rising sodium and high serum osmolality, not a potassium problem, and mislabeling true diabetes insipidus as benign diuresis risks progressive hypernatremia."},{"text":"Start a furosemide infusion to manage the high urine output and prevent volume overload","label":"D","correct":false,"rationale":"A loop diuretic would aggravate the already large free-water and volume losses of diabetes insipidus and worsen hypernatremia, making it exactly the wrong intervention."},{"text":"Obtain an urgent CT head to evaluate for cerebral salt wasting before initiating any therapy","label":"E","correct":false,"rationale":"Cerebral salt wasting causes hyponatremia with true volume depletion, not hypernatremia with dilute urine, so this misidentifies the syndrome and delays appropriate desmopressin therapy."}]'::jsonb, 'A', 'Manipulation of the posterior pituitary stalk during transsphenoidal surgery commonly produces transient central diabetes insipidus, especially with macroadenomas that have suprasellar extension. The diagnostic triad is hypotonic polyuria (often greater than 300 mL/hr of dilute urine), a rising serum sodium with elevated serum osmolality, and inappropriately low urine osmolality. Treatment is to replace the free-water deficit and ongoing losses and to administer desmopressin (DDAVP), a selective V2 agonist, while monitoring electrolytes closely to avoid overcorrection and iatrogenic SIADH-type hyponatremia. The condition is usually self-limited but must be distinguished from cerebral salt wasting and SIADH, which present with hyponatremia.', '{}'::jsonb, 'Subspecialty Care', 'Central diabetes insipidus after transsphenoidal pituitary surgery', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK554582/","source":"Desmopressin - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Neuro'),
('authored-batch-r20-027', 'Obstetric', 'A 27-year-old G1P0 at 40 weeks (BMI 29) requests labor analgesia at 5 cm dilation. She is contracting on an oxytocin infusion. A combined spinal-epidural (CSE) is placed with intrathecal fentanyl 25 mcg plus bupivacaine 2.5 mg, and she reports near-complete pain relief within 3 minutes. Maternal blood pressure is 118/72 mmHg (baseline 120/74) and she is positioned with left uterine displacement. Approximately 5 minutes after the intrathecal dose, the fetal heart tracing shows a prolonged deceleration to 70/min, and the tocodynamometer reveals uterine tachysystole with elevated baseline tone. Which mechanism best explains this fetal heart rate change, and what is the most appropriate immediate intervention?', '[{"text":"Maternal hypotension from sympathetic blockade has reduced uteroplacental perfusion; treat with a 500 mL fluid bolus and IV phenylephrine","label":"A","correct":false,"rationale":"Incorrect: her blood pressure is essentially at baseline with no hypotension, so vasopressor-treated hypotension is not the operative mechanism for this bradycardia."},{"text":"An abrupt fall in maternal epinephrine from rapid analgesia has removed tocolytic tone, causing uterine tachysystole and reduced placental perfusion; stop the oxytocin and consider a tocolytic such as terbutaline or nitroglycerin","label":"B","correct":true,"rationale":"Correct: rapid pain relief (especially with the intrathecal opioid of a CSE) sharply lowers circulating epinephrine, whose beta-2 tocolytic effect is lost, producing uterine hypertonus/tachysystole and transient fetal bradycardia best managed by discontinuing oxytocin and uterine relaxation."},{"text":"Direct fetal myocardial depression from systemic absorption of intrathecal fentanyl; administer naloxone to the mother","label":"C","correct":false,"rationale":"Incorrect: the minute intrathecal fentanyl dose produces negligible fetal systemic levels and does not cause fetal bradycardia, so maternal naloxone is not indicated."},{"text":"An unrecognized high spinal has caused maternal bradycardia transmitted to the fetus; give atropine and prepare for intubation","label":"D","correct":false,"rationale":"Incorrect: a high spinal would produce maternal hypotension, bradycardia, and respiratory compromise, none of which are present, and fetal heart rate is not simply a reflection of maternal rate."},{"text":"Aortocaval compression from supine positioning has reduced venous return; reposition the patient fully supine to improve cardiac output","label":"E","correct":false,"rationale":"Incorrect: she is already in left uterine displacement, and placing a term parturient supine would worsen aortocaval compression rather than help."}]'::jsonb, 'B', 'Fetal bradycardia after neuraxial labor analgesia, more common with CSE than epidural alone, is classically caused by uterine tachysystole rather than maternal hypotension. The abrupt analgesia lowers maternal plasma epinephrine, whose beta-2 effect normally relaxes the uterus; its withdrawal leaves unopposed oxytocin and norepinephrine, producing hypertonus that reduces uteroplacental blood flow. The episode is usually transient and responds to intrauterine resuscitation: left uterine displacement, treating any hypotension, oxygen, stopping oxytocin, and uterine relaxation (terbutaline or nitroglycerin) if it persists.', '{}'::jsonb, 'Subspecialty Care', 'Neuraxial labor analgesia complications — CSE-associated fetal bradycardia from uterine tachysystole', 'medium', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC9391899/","source":"Neuraxial labor analgesia: a literature review (PMC)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-028', 'Obstetric', 'A 32-year-old woman at 19 weeks gestation requires laparoscopic appendectomy for acute appendicitis. She has no other medical history; vital signs and labs are normal. The obstetric team confirms a viable fetus with a normal preoperative fetal heart rate. The surgeon asks whether the operation should proceed now or be delayed, and the anesthesia team plans general anesthesia. Which statement best reflects appropriate management of this pregnant patient undergoing non-obstetric surgery?', '[{"text":"Surgery should be postponed until after delivery because all volatile anesthetics are proven human teratogens at clinical concentrations","label":"A","correct":false,"rationale":"Incorrect: no commonly used anesthetic agent has been definitively shown to be teratogenic in humans at clinical doses, and necessary surgery for acute appendicitis should not be deferred."},{"text":"Regional anesthesia is mandatory because general anesthesia is contraindicated in any pregnant patient after the first trimester","label":"B","correct":false,"rationale":"Incorrect: general anesthesia is not contraindicated in pregnancy, and the technique should be chosen on surgical and patient grounds, not by a blanket prohibition."},{"text":"Necessary surgery should proceed promptly with attention to avoiding maternal hypoxemia, hypotension, and hypocapnia or hypercapnia, aspiration prophylaxis and rapid-sequence induction as indicated, and left uterine displacement once the gravid uterus warrants it","label":"C","correct":true,"rationale":"Correct: an acutely needed operation should not be delayed, and fetal well-being is best protected by maintaining maternal oxygenation, normotension, and normocapnia while attending to aspiration risk and aortocaval compression."},{"text":"Nitrous oxide should be used as the primary agent to minimize fetal exposure to halogenated volatiles","label":"D","correct":false,"rationale":"Incorrect: nitrous oxide is not a preferred primary agent given theoretical concerns about methionine synthase inhibition, and there is no requirement to avoid halogenated volatiles, which are not proven human teratogens."},{"text":"Continuous intraoperative electronic fetal heart rate monitoring is required at this gestational age to guide anesthetic management","label":"E","correct":false,"rationale":"Incorrect: at 19 weeks the fetus is previable, so documenting fetal heart rate before and after the procedure is reasonable, but continuous intraoperative monitoring is reserved for viable gestations when intervention would be considered."}]'::jsonb, 'C', 'Up to about 2% of pregnant women undergo non-obstetric surgery, and urgent operations such as appendectomy should never be denied. When elective, surgery is ideally deferred to the second trimester or after delivery, but the priority for any anesthetic is maintaining the maternal physiology that supports the fetus: adequate oxygenation, normotension, and normocapnia, plus aspiration prophylaxis and left uterine displacement once the uterus is large enough. No standard anesthetic agent is a proven human teratogen at clinical doses. Continuous intraoperative fetal monitoring is generally reserved for viable gestations where the team would act on the tracing.', '{}'::jsonb, 'Subspecialty Care', 'Anesthesia for non-obstetric surgery during pregnancy — timing, agent safety, and fetal monitoring', 'hard', '[{"url":"https://pmc.ncbi.nlm.nih.gov/articles/PMC12028341/","source":"Anesthetic Management of the Pregnant Patient Undergoing Non-Obstetric Surgery (PMC)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-029', 'Obstetric', 'A 33-year-old G2P2 woman is in the PACU after a cesarean delivery under spinal anesthesia. She has a history of moderate persistent asthma and gestational hypertension, with a current blood pressure of 158/96 mmHg. The obstetrician reports ongoing uterine atony with brisk bleeding that has not responded adequately to an oxytocin infusion, and requests a second-line uterotonic. Which agent is the most appropriate next choice given this patient''s comorbidities?', '[{"text":"Methylergonovine (methylergometrine) 0.2 mg intramuscularly","label":"A","correct":false,"rationale":"Incorrect: as an ergot alkaloid with alpha-adrenergic activity it can cause severe vasoconstriction and a hypertensive crisis, so it is relatively contraindicated in this hypertensive patient."},{"text":"Carboprost (15-methyl prostaglandin F2-alpha) 250 mcg intramuscularly","label":"B","correct":false,"rationale":"Incorrect: carboprost is a potent bronchoconstrictor and is relatively contraindicated in asthma, making it a poor choice for this patient."},{"text":"A repeat bolus of intravenous ergonovine to rapidly augment uterine tone","label":"C","correct":false,"rationale":"Incorrect: ergonovine is the same ergot-alkaloid class as methylergonovine and carries the same hypertensive risk, so it is contraindicated here for the identical reason."},{"text":"Misoprostol (prostaglandin E1) 800 to 1000 mcg administered rectally","label":"D","correct":true,"rationale":"Correct: misoprostol lacks both the ergot-mediated hypertensive effect and the bronchoconstriction of carboprost, so it is the safest second-line uterotonic for a patient with both hypertension and asthma."},{"text":"Additional intravenous oxytocin given as a rapid undiluted bolus","label":"E","correct":false,"rationale":"Incorrect: atony has already failed to respond to oxytocin, and a rapid undiluted bolus can cause profound hypotension and tachycardia, so escalating oxytocin is neither effective nor safe."}]'::jsonb, 'D', 'When first-line oxytocin fails to control atonic postpartum hemorrhage, the choice of second-line uterotonic is dictated by comorbidities. Ergot alkaloids (methylergonovine, ergonovine) are alpha-adrenergic agonists that cause vasoconstriction and are relatively contraindicated in hypertension, while carboprost (15-methyl PGF2-alpha) causes bronchospasm and is relatively contraindicated in asthma. Misoprostol, a prostaglandin E1 analog, avoids both hazards and is the appropriate agent for a parturient who is both hypertensive and asthmatic.', '{}'::jsonb, 'Subspecialty Care', 'Postpartum hemorrhage — uterotonic selection by comorbidity (ergot in hypertension, carboprost in asthma)', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499988/","source":"Postpartum Hemorrhage (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', 'Obstetric'),
('authored-batch-r20-030', 'Ambulatory', 'A 3-year-old, 15-kg boy is scheduled for elective bilateral myringotomy and tube placement at a freestanding ambulatory surgery center. On the morning of surgery his mother reports a clear runny nose and an occasional dry cough for the past two days. He is afebrile (37.1 C), playful and interactive, eating normally, with clear lungs and an SpO2 of 99% on room air. There is no history of asthma, prematurity, or secondhand smoke exposure, and the procedure is brief and does not require endotracheal intubation. Which of the following is the most appropriate management decision?', '[{"text":"Postpone the case and reschedule in 4 to 6 weeks because any current upper respiratory infection mandates cancellation","label":"A","correct":false,"rationale":"Blanket cancellation for an uncomplicated, afebrile URI without lower-airway signs is outdated and overly conservative, exposing the family to unnecessary rescheduling for a brief, low-risk procedure."},{"text":"Postpone the case for 2 weeks because the residual airway hyperreactivity window makes adverse events more likely if surgery proceeds now","label":"B","correct":false,"rationale":"Airway hyperreactivity can persist for weeks, but a child with only mild coryza and no high-risk features (fever, wheeze, purulent secretions, lethargy) does not meet criteria for postponement, and delaying does not reliably reduce risk for this low-acuity case."},{"text":"Proceed only after placing an endotracheal tube to definitively secure the airway against laryngospasm","label":"C","correct":false,"rationale":"Endotracheal intubation increases, rather than decreases, the risk of laryngospasm and bronchospasm in a child with a URI and is unnecessary for a brief myringotomy that is routinely done with a natural airway."},{"text":"Proceed but pretreat with intramuscular atropine and a prophylactic dose of intravenous dexamethasone to eliminate the risk of laryngospasm","label":"D","correct":false,"rationale":"Neither routine anticholinergic nor steroid prophylaxis reliably prevents laryngospasm, and committing to IM injection and IV access is excessive for an otherwise straightforward mask anesthetic in a mildly symptomatic child."},{"text":"Proceed with general anesthesia, favoring an inhalational technique with a natural airway and avoiding instrumentation of the trachea","label":"E","correct":true,"rationale":"Correct: with only mild, uncomplicated URI symptoms and no high-risk features, this brief myringotomy is appropriately performed under mask/natural-airway general anesthesia, which minimizes airway instrumentation and the associated risk of perioperative respiratory adverse events."}]'::jsonb, 'E', 'Children with a current or recent URI have roughly a 2- to 3-fold higher risk of perioperative respiratory adverse events (laryngospasm, bronchospasm, desaturation), but contemporary practice individualizes the decision rather than cancelling reflexively. Red flags that favor postponement include fever, mucopurulent secretions, wheezing or a moist productive cough, lethargy, and high-risk surgery; a child with mild clear rhinorrhea who is afebrile and active is generally safe to anesthetize. Minimizing airway instrumentation (natural airway/mask or LMA rather than an ETT) is a key risk-reduction strategy for a brief ambulatory procedure.', '{}'::jsonb, 'Subspecialty Care', 'Pediatric upper respiratory infection and perioperative respiratory adverse events in ambulatory surgery', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/pediatric-upper-respiratory-infection-and-anesthesia/","source":"Pediatric Upper Respiratory Infection and Anesthesia - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Ambulatory');
